// ************************************
//  Enablers
// ************************************
instance SimulinkTool : DTDFVocab:Enabler [
    base:desc "Simulink (MATLAB) simulation platform used for component dynamics, gearboxes, and friction modeling."
    DTDFVocab:enables SimulationService
]

instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker used to transmit real‑time sensor data streams from PLC to the digital twin."
    DTDFVocab:enables DataTransmissionService
]

