    base:desc "Enables ontology‑based linking and traceability of data traces via the Asset Administration Shell."
    DTDFVocab:enables DataLinkingService
]

instance WebDashboardEnabler : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard application used to visualise measured and simulated data traces in real‑time."
    DTDFVocab:enables DataVisualizationService
]

